// File: MusicService.kt
import android.app.*
import android.content.Intent
import android.os.IBinder
import androidx.core.app.NotificationCompat

class MusicService : Service() {
  companion object {
    const val CHANNEL_ID = "music_channel"
    const val NOTIF_ID = 1
  }

  override fun onBind(intent: Intent?): IBinder? = null   // not bound

  override fun onCreate() {
    super.onCreate()
    createNotificationChannel()
  }

  override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
    // MUST call startForeground within a few seconds of onStartCommand or the system kills us
    startForeground(NOTIF_ID, buildNotification("Playing…"))
    // Kick off actual playback (on a background dispatcher — Service itself is on main thread)
    // playbackScope.launch { player.play(track) }
    return START_STICKY   // restart if system kills us later
  }

  private fun buildNotification(text: String): Notification =
    NotificationCompat.Builder(this, CHANNEL_ID)
      .setContentTitle("MyMusic")
      .setContentText(text)
      .setSmallIcon(android.R.drawable.ic_media_play)
      .setOngoing(true)
      .build()

  private fun createNotificationChannel() {
    val channel = NotificationChannel(CHANNEL_ID, "Music", NotificationManager.IMPORTANCE_LOW)
    getSystemService(NotificationManager::class.java).createNotificationChannel(channel)
  }
}

